// Flaky fix: replace a racy fixed wait with a deterministic condition

// BEFORE (flaky): asserts before the chart may have rendered
await page.waitForTimeout(1000);
expect(await page.locator('#chart').isVisible()).toBe(true);

// AFTER (stable): wait on the actual condition with a generous timeout
await expect(page.locator('#chart')).toBeVisible({ timeout: 10000 });

// Reading a failure to triage it:
// AssertionError: expected status 200, got 403   -> auth/permission bug or wrong token (env)
// TimeoutError: locator('#chart') not visible      -> timing/flaky or missing element (bug)
// Error: connect ECONNREFUSED 127.0.0.1:8080       -> environment: app not running
