```typescript
// playwright.config.ts — one config, layered with env overrides and multiple projects
import { defineConfig, devices } from '@playwright/test';

export default defineConfig({
  use: {
    baseURL: process.env.BASE_URL || 'http://localhost:3000',
    actionTimeout: 15000,
  },
  timeout: 30000,                          // per-test timeout
  retries: process.env.CI ? 2 : 0,         // retries in CI only
  workers: process.env.CI ? 4 : undefined, // parallelism
  reporter: [['junit', { outputFile: 'results.xml' }], ['html']],
  projects: [
    { name: 'chromium', use: { ...devices['Desktop Chrome'] } },
    { name: 'firefox',  use: { ...devices['Desktop Firefox'] } },
    { name: 'webkit',   use: { ...devices['Desktop Safari'] } },
  ],
});
```

